touch core/formatting/SuperFormatter.py


📜 2. Contenu de SuperFormatter.py
pythonCopierModifierimport json

class SuperFormatter:
    @staticmethod
    def render(value, target="IA", meta=None):
        """
        value : le résultat brut
        target : type d'utilisateur (IA, CLI, API, etc.)
        meta : dict facultatif précisant le format de sortie autorisé ou forcé
        """
        output_rules = meta.get("output_format") if meta else {}
        default_format = output_rules.get("default", "json_nested")
        allowed = output_rules.get("allowed", ["json_nested", "flat_list", "string", "markdown"])
        forbidden = output_rules.get("forbidden", [])

        # Choix du format
        format_type = default_format
        if format_type in forbidden:
            format_type = "string"

        # Application du format
        if format_type == "json_nested":
            return value

        if format_type == "flat_list":
            return SuperFormatter._to_flat_list(value)

        if format_type == "string":
            return SuperFormatter._to_string(value)

        if format_type == "markdown":
            return SuperFormatter._to_markdown(value)

        return value  # fallback

    @staticmethod
    def _to_flat_list(value):
        if not isinstance(value, list):
            return [{"value": value}]
        return [
            {
                "type": node.get("type"),
                "name": node.get("name"),
                "path": node.get("prefix", "") + node.get("name", "")
            }
            for node in value
        ]

    @staticmethod
    def _to_string(value):
        if isinstance(value, list):
            return "\n".join([v.get("prefix", "") + v.get("name", "") for v in value])
        return str(value)

    @staticmethod
    def _to_markdown(value):
        if isinstance(value, list):
            return "\n".join(["- " + v.get("prefix", "") + "**" + v.get("name", "") + "**" for v in value])
        return f"`{str(value)}`"


